func newTrustPendingCmd(deps TrustDeps) *cobra.Command {
	var asJSON bool
	cmd := &cobra.Command{
		Use:   "pending",
		Short: "List SHAs observed during sync that need review",
		RunE: func(cmd *cobra.Command, _ []string) error {
			p, err := resolvePendingStore(deps)
			if err != nil {
				return err
			}
			latest, err := p.Latest()
			if err != nil {
				return err
			}
			out := outWriter(deps, cmd)
			return printPending(out, latest, asJSON)
		},
	}
	cmd.Flags().BoolVar(&asJSON, "json", false, "emit JSON instead of text")
	return cmd
}

func printPending(out io.Writer, latest map[string]trust.PendingEntry, asJSON bool) error {
	rows := make([]trust.PendingEntry, 0, len(latest))
	for _, e := range latest {
		rows = append(rows, e)
	}
	sort.Slice(rows, func(i, j int) bool { return rows[i].URL < rows[j].URL })
	if asJSON {
		enc := json.NewEncoder(out)
		enc.SetIndent("", "  ")
		return enc.Encode(rows)
	}
	for _, r := range rows {
		fmt.Fprintf(out, "%s\t%s -> %s\t%s\n", r.URL, shortSHAOrDash(r.OldSHA), shortSHAOrDash(r.NewSHA), r.TSRaw)
