140	// rewrite filters pending entries through keep and rewrites the file.
141	// Advisory-locked via gofrs/flock; on absent file, returns nil.
142	func (p *PendingStore) rewrite(keep func(PendingEntry) bool) error {
143		p.mu.Lock()
144		defer p.mu.Unlock()
145	
146		entries, err := p.List()
147		if err != nil {
148			return err
149		}
150		if len(entries) == 0 {
151			return nil
152		}
153	
154		lockPath := p.path + ".lock"
155		lk := flock.New(lockPath)
156		ctx, cancel := context.WithTimeout(context.Background(), compactLockTimeout)
157		defer cancel()
158		locked, err := lk.TryLockContext(ctx, 50*time.Millisecond)
159		if err != nil {
160			return fmt.Errorf("trust: acquire pending lock: %w", err)
161		}
162		if !locked {
163			return ErrLocked
164		}
165		defer func() { _ = lk.Unlock() }()
166	
167		dir := filepath.Dir(p.path)
168		tmp, err := os.CreateTemp(dir, "pending-*.jsonl.tmp")
169		if err != nil {
170			return fmt.Errorf("trust: create pending tmp: %w", err)
171		}
172		tmpPath := tmp.Name()
173		removeTmp := true
174		defer func() {
175			if removeTmp {
176				_ = os.Remove(tmpPath)
177			}
178		}()
179	
180		w := bufio.NewWriter(tmp)
181		kept := 0
182		for _, e := range entries {
183			if !keep(e) {
184				continue
185			}
186			buf, err := marshalPendingEntry(e)
187			if err != nil {
188				_ = tmp.Close()
189				return err
190			}
191			if _, err := w.Write(buf); err != nil {
192				_ = tmp.Close()
193				return fmt.Errorf("trust: write pending tmp: %w", err)
194			}
195			kept++
196		}
197		if err := w.Flush(); err != nil {
198			_ = tmp.Close()
199			return fmt.Errorf("trust: flush pending tmp: %w", err)
200		}
201		if err := tmp.Chmod(0o600); err != nil {
202			_ = tmp.Close()
203			return fmt.Errorf("trust: chmod pending tmp: %w", err)
204		}
205		if err := tmp.Close(); err != nil {
206			return fmt.Errorf("trust: close pending tmp: %w", err)
207		}
208	
209		if kept == 0 {
210			// No survivors — remove the original rather than leaving an empty file.
211			if err := os.Remove(p.path); err != nil && !errors.Is(err, os.ErrNotExist) {
212				return fmt.Errorf("trust: remove empty pending: %w", err)
213			}
214			return nil
215		}
216	
217		if err := os.Rename(tmpPath, p.path); err != nil {
218			return fmt.Errorf("trust: rename pending tmp: %w", err)
219		}
220		removeTmp = false
221		return nil
222	}
223	
224	// validatePendingEntry checks structural invariants.
225	func validatePendingEntry(e PendingEntry) error {
226		if e.URL == "" {
227			return errors.New("trust: pending: url is required")
228		}
229		if e.TSRaw == "" {
230			return errors.New("trust: pending: ts is required")
231		}
232		if !IsSHA40(e.NewSHA) {
233			return fmt.Errorf("trust: pending: new_sha must be 40-hex, got %q", e.NewSHA)
234		}
235		if e.OldSHA != "" && !IsSHA40(e.OldSHA) {
236			return fmt.Errorf("trust: pending: old_sha must be empty or 40-hex, got %q", e.OldSHA)
237		}
238		return nil
239	}
240	
241	// marshalPendingEntry serializes e to one JSONL line including trailing
242	// newline.
243	func marshalPendingEntry(e PendingEntry) ([]byte, error) {
244		if e.TSRaw == "" && !e.TS.IsZero() {
245			e.TSRaw = e.TS.UTC().Format(time.RFC3339)
246		}
247		b, err := json.Marshal(e)
248		if err != nil {
249			return nil, fmt.Errorf("trust: marshal pending: %w", err)
250		}
251		return append(b, '\n'), nil
252	}
253	
254	// parsePendingLines decodes pending.jsonl.
255	func parsePendingLines(r *os.File, path string) ([]PendingEntry, error) {
256		sc := bufio.NewScanner(r)
257		sc.Buffer(make([]byte, 0, 64<<10), 1<<20)
258	
259		var out []PendingEntry
260		lineNo := 0
261		for sc.Scan() {
262			lineNo++
263			line := sc.Bytes()
264			if len(line) == 0 {
265				continue
266			}
267			var e PendingEntry
268			if err := json.Unmarshal(line, &e); err != nil {
269				return nil, fmt.Errorf("trust: parse pending %s line %d: %w", path, lineNo, err)
270			}
271			if e.TSRaw != "" {
272				if t, err := time.Parse(time.RFC3339, e.TSRaw); err == nil {
273					e.TS = t
274				}
275			}
276			out = append(out, e)
277		}
278		if err := sc.Err(); err != nil {
279			return nil, fmt.Errorf("trust: scan pending %s: %w", path, err)
280		}
281		return out, nil

