19	// CompactThresholdBytes is the file size above which `aienvs trust compact`
20	// suggests rotating. Compact() itself runs unconditionally; callers decide
21	// when to invoke it.
22	const CompactThresholdBytes int64 = 1 << 20 // 1 MiB
23	
24	// compactLockTimeout bounds how long Compact waits for the advisory lock
25	// before giving up with ErrLocked.
26	const compactLockTimeout = 5 * time.Second
27	
28	// ErrLocked is returned when Compact cannot acquire the advisory lock in
29	// compactLockTimeout.
30	var ErrLocked = errors.New("trust: store busy, another compact is in progress")
31	
32	// Store owns the append-only trust.jsonl file described in
33	// docs/spec/trust-store-v1.md.
34	//
35	// A Store value is safe for concurrent use from multiple goroutines. Cross
36	// process concurrency is handled by atomic single-write appends (for
37	// Append) and by a gofrs/flock advisory lock on a sibling *.lock file (for
38	// Compact).
39	type Store struct {
40		path string
41		mu   sync.Mutex
42	}
43	
44	// NewStore returns a Store rooted at path. The file and its parent
45	// directory are created lazily on first Append.
46	func NewStore(path string) *Store {
47		return &Store{path: path}
48	}
49	
50	// Path returns the absolute path to trust.jsonl.
51	func (s *Store) Path() string {
52		return s.path
53	}
54	
55	// Append validates and appends e to the log. It creates the parent
56	// directory (mode 0700) and file (mode 0600) on first use.
57	//
58	// The in-process mutex guards against intra-process write interleaving.
59	// Cross-process interleaving is prevented by the single write(2) call
60	// (atomic up to PIPE_BUF for POSIX; FILE_APPEND_DATA with OVERLAPPED
61	// Offset=-1 semantics on Windows via os.O_APPEND).
62	func (s *Store) Append(e LogEntry) error {
63		if err := ValidateEntry(e); err != nil {
64			return err
65		}
66	
67		buf, err := marshalEntry(e)
68		if err != nil {
69			return err
70		}
71	
72		s.mu.Lock()
73		defer s.mu.Unlock()
74	
75		if err := os.MkdirAll(filepath.Dir(s.path), 0o700); err != nil {
76			return fmt.Errorf("trust: mkdir store dir: %w", err)
77		}
78	
79		f, err := os.OpenFile(s.path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o600)
80		if err != nil {
81			return fmt.Errorf("trust: open store for append: %w", err)
82		}
83		defer func() { _ = f.Close() }()
84	
85		if _, err := f.Write(buf); err != nil {
86			return fmt.Errorf("trust: append write: %w", err)
87		}
88		return nil
89	}
