91	// Fold reads the log in order and returns the current state per URL.
92	// Absent file yields an empty map, not an error.
93	//
94	// Unknown ops are ignored to preserve forward compatibility. Malformed
95	// lines cause Fold to return an error with a line-number hint.
96	func (s *Store) Fold() (map[string]State, error) {
97		entries, err := s.ReadAll()
98		if err != nil {
99			return nil, err
100		}
101		return foldEntries(entries), nil
102	}
