104	// ReadAll returns every entry in order. Used by Compact and by diagnostic
105	// callers that want the raw history.
106	func (s *Store) ReadAll() ([]LogEntry, error) {
107		f, err := os.Open(s.path)
108		if err != nil {
109			if errors.Is(err, os.ErrNotExist) {
110				return nil, nil
111			}
112			return nil, fmt.Errorf("trust: open store: %w", err)
113		}
114		defer func() { _ = f.Close() }()
