119	// Compact rewrites the log, retaining the most-recent trust / promote /
120	// allow-new-shas-* record per URL plus every revoke record. It holds a
121	// gofrs/flock advisory lock on a sibling *.lock file for the duration of
122	// the rewrite.
123	//
124	// Concurrent Appends race harmlessly: an append to the pre-rename file is
125	// lost after rename, but callers at compact time are interactive by
126	// construction and can retry. See docs/spec/trust-store-v1.md.
127	func (s *Store) Compact() error {
128		entries, err := s.ReadAll()
129		if err != nil {
130			return err
131		}
132		if len(entries) == 0 {
133			return nil
134		}
135	
136		lockPath := s.path + ".lock"
137		lk := flock.New(lockPath)
138		ctx, cancel := context.WithTimeout(context.Background(), compactLockTimeout)
139		defer cancel()
140	
141		locked, err := lk.TryLockContext(ctx, 50*time.Millisecond)
142		if err != nil {
143			return fmt.Errorf("trust: acquire compact lock: %w", err)
144		}
145		if !locked {
146			return ErrLocked
147		}
148		defer func() { _ = lk.Unlock() }()
149	
150		kept := compactEntries(entries)
151	
152		// Write to sibling tmp, fsync, rename atomically over the original.
153		dir := filepath.Dir(s.path)
154		tmp, err := os.CreateTemp(dir, "trust-*.jsonl.tmp")
155		if err != nil {
156			return fmt.Errorf("trust: create compact tmp: %w", err)
157		}
158		tmpPath := tmp.Name()
159		// Best-effort cleanup if we return early.
160		removeTmp := true
161		defer func() {
162			if removeTmp {
163				_ = os.Remove(tmpPath)
164			}
165		}()
166	
167		w := bufio.NewWriter(tmp)
168		for _, e := range kept {
169			buf, err := marshalEntry(e)
170			if err != nil {
171				_ = tmp.Close()
172				return fmt.Errorf("trust: marshal during compact: %w", err)
173			}
174			if _, err := w.Write(buf); err != nil {
175				_ = tmp.Close()
176				return fmt.Errorf("trust: write during compact: %w", err)
177			}
178		}
179		if err := w.Flush(); err != nil {
180			_ = tmp.Close()
181			return fmt.Errorf("trust: flush compact tmp: %w", err)
182		}
183		if err := tmp.Chmod(0o600); err != nil {
184			_ = tmp.Close()
185			return fmt.Errorf("trust: chmod compact tmp: %w", err)
186		}
187		if err := tmp.Close(); err != nil {
188			return fmt.Errorf("trust: close compact tmp: %w", err)
189		}
190	
191		if err := os.Rename(tmpPath, s.path); err != nil {
192			return fmt.Errorf("trust: rename compact tmp: %w", err)
193		}
194		removeTmp = false
195		return nil
196	}
